INSERT INTO `course_lessons` VALUES (4,2,3,'Hand hygiene & infection control','<p>Hand hygiene is the single most effective way to prevent the spread of infection. Follow the WHO 5 moments for hand hygiene.</p>',1,'2026-07-08 11:17:24','2026-07-08 11:17:24'),(5,2,3,'Recording vital signs','<p>Vital signs include temperature, pulse, respiration, blood pressure and oxygen saturation. Accurate measurement and documentation are essential.</p>',2,'2026-07-08 11:17:24','2026-07-08 11:17:24'),(6,3,4,'Routes of administration','<p>Oral, intravenous, intramuscular, subcutaneous and topical routes — each has advantages and precautions.</p>',1,'2026-07-08 11:17:24','2026-07-08 11:17:24'),(7,4,5,'Introduction','<p>Welcome to the course. This lesson introduces the key concepts and learning outcomes.</p>',1,'2026-07-09 12:48:47','2026-07-09 12:48:47'),(8,5,6,'Introduction','<p>Welcome to the course. This lesson introduces the key concepts and learning outcomes.</p>',1,'2026-07-09 12:48:47','2026-07-09 12:48:47'),(9,6,7,'Introduction','<p>Welcome to the course. This lesson introduces the key concepts and learning outcomes.</p>',1,'2026-07-09 12:48:47','2026-07-09 12:48:47'),(10,7,8,'Introduction','<p>Welcome to the course. This lesson introduces the key concepts and learning outcomes.</p>',1,'2026-07-09 12:48:47','2026-07-09 12:48:47'),(14,4,5,'Core Principles','<p>This lesson covers the core principles and their practical application in nursing.</p>',2,'2026-07-09 12:48:47','2026-07-09 12:48:47'),(15,5,6,'Core Principles','<p>This lesson covers the core principles and their practical application in nursing.</p>',2,'2026-07-09 12:48:47','2026-07-09 12:48:47'),(16,6,7,'Core Principles','<p>This lesson covers the core principles and their practical application in nursing.</p>',2,'2026-07-09 12:48:47','2026-07-09 12:48:47'),(17,7,8,'Core Principles','<p>This lesson covers the core principles and their practical application in nursing.</p>',2,'2026-07-09 12:48:47','2026-07-09 12:48:47'),(21,2,13,'Course introduction & learning outcomes','<p>Welcome to <b>Nursing Practice</b>. By the end of this course you will be able to describe the core principles, apply them in a clinical setting, and demonstrate competency in the associated practical skills.</p><ul><li>Understand the scope of Nursing Practice.</li><li>Relate theory to nursing practice.</li><li>Prepare for CATs and the final assessment.</li></ul>',1,'2026-07-09 22:47:22','2026-07-09 22:47:22'),(22,2,13,'Key terminology & concepts','<p>This lesson covers the essential vocabulary used throughout Nursing Practice. Mastering these terms is the foundation for the clinical topics that follow.</p><p><b>Tip:</b> keep a running glossary in your notebook.</p>',2,'2026-07-09 22:47:22','2026-07-09 22:47:22'),(23,2,14,'Underlying theory','<p>We examine the theoretical framework behind Nursing Practice, including the evidence base and how guidelines are developed.</p><ol><li>Evidence-based practice.</li><li>Clinical reasoning.</li><li>Patient-centred care.</li></ol>',1,'2026-07-09 22:47:22','2026-07-09 22:47:22'),(24,2,14,'Clinical application','<p>How the principles translate at the bedside. We work through worked examples and common scenarios you will meet on placement.</p>',2,'2026-07-09 22:47:22','2026-07-09 22:47:22'),(25,2,15,'Procedure walkthrough','<p>A step-by-step walkthrough of the core procedure for Nursing Practice, with safety checks and documentation requirements.</p><ul><li>Preparation & consent.</li><li>Technique.</li><li>Aftercare & documentation.</li></ul>',1,'2026-07-09 22:47:22','2026-07-09 22:47:22'),(26,2,15,'Case study & discussion','<p>Read the case, identify the priorities, and outline your care plan. Bring your answers to the next live session.</p>',2,'2026-07-09 22:47:22','2026-07-09 22:47:22'),(27,2,16,'Revision summary','<p>A consolidated summary of everything covered. Use this alongside the coursework and quizzes to prepare for your CAT.</p>',1,'2026-07-09 22:47:22','2026-07-09 22:47:22'),(28,3,17,'Course introduction & learning outcomes','<p>Welcome to <b>Pharmacology</b>. By the end of this course you will be able to describe the core principles, apply them in a clinical setting, and demonstrate competency in the associated practical skills.</p><ul><li>Understand the scope of Pharmacology.</li><li>Relate theory to nursing practice.</li><li>Prepare for CATs and the final assessment.</li></ul>',1,'2026-07-09 22:47:22','2026-07-09 22:47:22'),(29,3,17,'Key terminology & concepts','<p>This lesson covers the essential vocabulary used throughout Pharmacology. Mastering these terms is the foundation for the clinical topics that follow.</p><p><b>Tip:</b> keep a running glossary in your notebook.</p>',2,'2026-07-09 22:47:22','2026-07-09 22:47:22'),(30,3,18,'Underlying theory','<p>We examine the theoretical framework behind Pharmacology, including the evidence base and how guidelines are developed.</p><ol><li>Evidence-based practice.</li><li>Clinical reasoning.</li><li>Patient-centred care.</li></ol>',1,'2026-07-09 22:47:22','2026-07-09 22:47:22'),(31,3,18,'Clinical application','<p>How the principles translate at the bedside. We work through worked examples and common scenarios you will meet on placement.</p>',2,'2026-07-09 22:47:22','2026-07-09 22:47:22'),(32,3,19,'Procedure walkthrough','<p>A step-by-step walkthrough of the core procedure for Pharmacology, with safety checks and documentation requirements.</p><ul><li>Preparation & consent.</li><li>Technique.</li><li>Aftercare & documentation.</li></ul>',1,'2026-07-09 22:47:22','2026-07-09 22:47:22'),(33,3,19,'Case study & discussion','<p>Read the case, identify the priorities, and outline your care plan. Bring your answers to the next live session.</p>',2,'2026-07-09 22:47:22','2026-07-09 22:47:22'),(34,3,20,'Revision summary','<p>A consolidated summary of everything covered. Use this alongside the coursework and quizzes to prepare for your CAT.</p>',1,'2026-07-09 22:47:22','2026-07-09 22:47:22'),(35,4,21,'Course introduction & learning outcomes','<p>Welcome to <b>Anatomy</b>. By the end of this course you will be able to describe the core principles, apply them in a clinical setting, and demonstrate competency in the associated practical skills.</p><ul><li>Understand the scope of Anatomy.</li><li>Relate theory to nursing practice.</li><li>Prepare for CATs and the final assessment.</li></ul>',1,'2026-07-09 22:47:22','2026-07-09 22:47:22'),(36,4,21,'Key terminology & concepts','<p>This lesson covers the essential vocabulary used throughout Anatomy. Mastering these terms is the foundation for the clinical topics that follow.</p><p><b>Tip:</b> keep a running glossary in your notebook.</p>',2,'2026-07-09 22:47:22','2026-07-09 22:47:22'),(37,4,22,'Underlying theory','<p>We examine the theoretical framework behind Anatomy, including the evidence base and how guidelines are developed.</p><ol><li>Evidence-based practice.</li><li>Clinical reasoning.</li><li>Patient-centred care.</li></ol>',1,'2026-07-09 22:47:22','2026-07-09 22:47:22'),(38,4,22,'Clinical application','<p>How the principles translate at the bedside. We work through worked examples and common scenarios you will meet on placement.</p>',2,'2026-07-09 22:47:22','2026-07-09 22:47:22'),(39,4,23,'Procedure walkthrough','<p>A step-by-step walkthrough of the core procedure for Anatomy, with safety checks and documentation requirements.</p><ul><li>Preparation & consent.</li><li>Technique.</li><li>Aftercare & documentation.</li></ul>',1,'2026-07-09 22:47:22','2026-07-09 22:47:22'),(40,4,23,'Case study & discussion','<p>Read the case, identify the priorities, and outline your care plan. Bring your answers to the next live session.</p>',2,'2026-07-09 22:47:22','2026-07-09 22:47:22'),(41,4,24,'Revision summary','<p>A consolidated summary of everything covered. Use this alongside the coursework and quizzes to prepare for your CAT.</p>',1,'2026-07-09 22:47:22','2026-07-09 22:47:22'),(42,5,25,'Course introduction