INSERT INTO `feedback` VALUES (1,'Great clinical exposure','The clinical placements this term were very well organised. Thank you.',231,2,NULL,1,1,1,2,'2026-07-09 12:46:33','2026-07-09 12:46:33'),(2,'Request for more lab time','Could we have additional practical sessions in the skills lab?',231,2,NULL,1,1,1,2,'2026-07-09 12:46:33','2026-07-09 12:46:33'),(3,'Appreciation from parent','Very happy with my child progress and the fee transparency.',NULL,2,33,2,4,1,2,'2026-07-09 12:46:33','2026-07-09 12:46:33'),(4,'Library hours','Kindly extend library opening hours during exams.',NULL,2,33,1,1,1,2,'2026-07-09 12:46:33','2026-07-09 12:46:33'),(5,'Excellent lecturers','The lecturers are supportive and knowledgeable.',231,2,NULL,1,1,1,2,'2026-07-09 12:46:33','2026-07-09 12:46:33');
