INSERT INTO `questions` VALUES (2,1,3,1,1,'Organs','easy','mcq','Which is the largest organ of the human body?','[\"Skin\", \"Liver\", \"Heart\", \"Brain\"]','0',2,'2026-07-08 14:18:58','2026-07-08 14:18:58'),(3,1,3,1,1,'Skeletal','medium','truefalse','The femur is located in the arm.','[\"True\", \"False\"]','false',1,'2026-07-08 14:18:58','2026-07-08 14:18:58'),(4,1,3,1,1,'Cardio','easy','truefalse','The human heart has four chambers.','[\"True\", \"False\"]','true',1,'2026-07-08 14:18:58','2026-07-08 14:18:58'),(5,1,3,1,1,'Cells','easy','short','What is the basic structural unit of life?',NULL,'cell',2,'2026-07-08 14:18:58','2026-07-08 14:18:58'),(6,1,3,1,1,'Organisation','medium','essay','Describe the levels of structural organisation in the human body.',NULL,NULL,5,'2026-07-08 14:18:58','2026-07-08 14:18:58'),(7,1,3,1,1,'Terminology','medium','mcq','The term \"anterior\" refers to which position?','[\"Front\", \"Back\", \"Above\", \"Below\"]','0',2,'2026-07-08 14:18:58','2026-07-08 14:18:58'),(8,1,3,1,5,'Infection control','easy','mcq','What is the single most effective way to prevent the spread of infection?','[\"Hand hygiene\", \"Gloves\", \"Masks\", \"Gowns\"]','0',2,'2026-07-08 14:18:58','2026-07-08 14:18:58'),(9,1,3,1,5,'Vitals','easy','truefalse','Blood pressure is one of the vital signs.','[\"True\", \"False\"]','true',1,'2026-07-08 14:18:58','2026-07-08 14:18:58'),(10,1,3,1,5,'Vitals','medium','short','What is the lower bound of a normal adult resting heart rate (bpm)?',NULL,'60',1,'2026-07-08 14:18:58','2026-07-08 14:18:58'),(11,1,3,1,5,'Documentation','medium','essay','Explain why accurate documentation of vital signs is important in nursing.',NULL,NULL,4,'2026-07-08 14:18:58','2026-07-08 14:18:58'),(12,1,3,1,1,'Skeletal System','easy','mcq','How many bones are in the adult human body?','[\"206\", \"201\", \"210\", \"198\"]','0',2,'2026-07-09 12:48:47','2026-07-09 12:48:47'),(13,1,3,1,1,'Skeletal System','medium','truefalse','The sternum is part of the axial skeleton.',NULL,'true',1,'2026-07-09 12:48:47','2026-07-09 12:48:47'),(14,1,3,1,2,'Cardiovascular','medium','mcq','Which chamber pumps blood to the lungs?','[\"Right ventricle\", \"Left ventricle\", \"Right atrium\", \"Left atrium\"]','0',2,'2026-07-09 12:48:47','2026-07-09 12:48:47'),(15,1,3,1,2,'Respiration','easy','truefalse','The diaphragm contracts during inspiration.',NULL,'true',1,'2026-07-09 12:48:47','2026-07-09 12:48:47'),(16,1,3,1,3,'Drug Classes','hard','mcq','Which class of drugs lowers blood pressure by blocking beta receptors?','[\"Beta blockers\", \"Diuretics\", \"ACE inhibitors\", \"Statins\"]','0',2,'2026-07-09 12:48:47','2026-07-09 12:48:47'),(17,1,3,1,3,'Dosage','medium','short','What does the abbreviation PRN mean on a prescription?',NULL,'as needed',2,'2026-07-09 12:48:47','2026-07-09 12:48:47'),(18,1,3,1,4,'Microorganisms','easy','mcq','Which of these is a bacterium?','[\"E. coli\", \"Influenza\", \"HIV\", \"Candida\"]','0',2,'2026-07-09 12:48:47','2026-07-09 12:48:47'),(19,1,3,1,4,'Asepsis','medium','truefalse','Hand hygiene is the single most effective infection-control measure.',NULL,'true',1,'2026-07-09 12:48:47','2026-07-09 12:48:47'),(20,1,3,1,5,'Vital Signs','easy','short','What is the normal adult resting heart rate range (bpm)?',NULL,'60-100',2,'2026-07-09 12:48:47','2026-07-09 12:48:47'),(21,1,3,1,5,'Nursing Process','hard','essay','Describe the five steps of the nursing process.',NULL,NULL,5,'2026-07-09 12:48:47','2026-07-09 12:48:47'),(22,1,3,2,6,'Anatomy','medium','mcq','The largest bone in the human body is the?','[\"Femur\", \"Tibia\", \"Humerus\", \"Fibula\"]','0',2,'2026-07-09 12:48:47','2026-07-09 12:48:47'),(23,1,3,2,7,'Physiology','easy','truefalse','Insulin lowers blood glucose levels.',NULL,'true',1,'2026-07-09 12:48:47','2026-07-09 12:48:47');
