INSERT INTO `syllabuses` VALUES (2,'Anatomy — Course syllabus',1,2,1,'sample-syllabus.txt','<h4>Course description</h4><p>This syllabus outlines the <b>Anatomy</b> unit for Certificate Year 1 at The Karen Hospital Medical Training College. It sets out the topics, learning outcomes, assessment structure and recommended materials for the unit.</p><h4>Learning outcomes</h4><p>By the end of this unit the student will be able to:</p><ul><li>Explain the fundamental principles of Anatomy.</li><li>Relate Anatomy theory to safe, evidence-based nursing practice.</li><li>Demonstrate competence in the associated clinical/practical skills.</li><li>Apply critical reasoning to case-based scenarios.</li></ul><h4>Topics covered</h4><ol><li>Introduction &amp; foundations of Anatomy</li><li>Core principles and underlying theory</li><li>Clinical / practical application</li><li>Documentation, safety and professional practice</li><li>Assessment and revision</li></ol><h4>Assessment</h4><p>Continuous assessment through <b>CAT 1</b> and <b>CAT 2</b>, coursework and quizzes, followed by a <b>Final Exam</b>. All marks contribute to the end-of-year gradebook and transcript.</p><h4>Recommended materials</h4><ul><li>Core textbook and lecture notes (see <i>Courses &rarr; Anatomy</i>).</li><li>Supplementary readings and handouts provided in class.</li><li>Online resources shared via the course hub.</li></ul>',1,2,'2026-07-08 11:31:55','2026-07-09 23:16:05'),(3,'Physiology — Course syllabus',1,1,2,'sample-syllabus.txt','<h4>Course description</h4><p>This syllabus outlines the <b>Physiology</b> unit for Certificate Year 1 at The Karen Hospital Medical Training College. It sets out the topics, learning outcomes, assessment structure and recommended materials for the unit.</p><h4>Learning outcomes</h4><p>By the end of this unit the student will be able to:</p><ul><li>Explain the fundamental principles of Physiology.</li><li>Relate Physiology theory to safe, evidence-based nursing practice.</li><li>Demonstrate competence in the associated clinical/practical skills.</li><li>Apply critical reasoning to case-based scenarios.</li></ul><h4>Topics covered</h4><ol><li>Introduction &amp; foundations of Physiology</li><li>Core principles and underlying theory</li><li>Clinical / practical application</li><li>Documentation, safety and professional practice</li><li>Assessment and revision</li></ol><h4>Assessment</h4><p>Continuous assessment through <b>CAT 1</b> and <b>CAT 2</b>, coursework and quizzes, followed by a <b>Final Exam</b>. All marks contribute to the end-of-year gradebook and transcript.</p><h4>Recommended materials</h4><ul><li>Core textbook and lecture notes (see <i>Courses &rarr; Physiology</i>).</li><li>Supplementary readings and handouts provided in class.</li><li>Online resources shared via the course hub.</li></ul>',1,2,'2026-07-08 11:31:55','2026-07-09 23:16:05'),(4,'Physiology — Course syllabus',1,2,2,'sample-syllabus.txt','<h4>Course description</h4><p>This syllabus outlines the <b>Physiology</b> unit for Certificate Year 1 at The Karen Hospital Medical Training College. It sets out the topics, learning outcomes, assessment structure and recommended materials for the unit.</p><h4>Learning outcomes</h4><p>By the end of this unit the student will be able to:</p><ul><li>Explain the fundamental principles of Physiology.</li><li>Relate Physiology theory to safe, evidence-based nursing practice.</li><li>Demonstrate competence in the associated clinical/practical skills.</li><li>Apply critical reasoning to case-based scenarios.</li></ul><h4>Topics covered</h4><ol><li>Introduction &amp; foundations of Physiology</li><li>Core principles and underlying theory</li><li>Clinical / practical application</li><li>Documentation, safety and professional practice</li><li>Assessment and revision</li></ol><h4>Assessment</h4><p>Continuous assessment through <b>CAT 1</b> and <b>CAT 2</b>, coursework and quizzes, followed by a <b>Final Exam</b>. All marks contribute to the end-